def get_sidebar_html(active_page="Home"):
    pages = [
        {"name": "Home", "icon": "home", "url": "/", "title": "Home"},
        {"name": "About", "icon": "info", "url": "/about", "title": "About"},
        {"name": "Data", "icon": "query_stats", "url": "/data_exploration", "title": "Data Exploration"},
        {"name": "Optimize", "icon": "settings_input_component", "url": "/optimization", "title": "Optimization"},
        {"name": "Top Stocks", "icon": "military_tech", "url": "/top_stocks", "title": "Top Stocks"}
    ]
    
    links_html = ""
    for page in pages:
        active_class = "active" if page["name"] == active_page else ""
        icon_fill = "font-variation-settings: 'FILL' 1;" if page["name"] == active_page else ""
        links_html += f"""<a class="sidebar-link {active_class}" href="{page['url']}" target="_self" title="{page['title']}"><span class="material-symbols-outlined" style="{icon_fill}">{page['icon']}</span><span class="sidebar-link-text">{page['name']}</span></a>"""

    html = f"""<link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&display=swap" rel="stylesheet"/><link href="https://fonts.googleapis.com/css2?family=Space+Mono:ital,wght@0,400;0,700;1,400;1,700&family=Space+Grotesk:wght@300..700&family=Geist:wght@100..900&display=swap" rel="stylesheet"/><style>[data-testid="stSidebar"] {{ display: none !important; }} header[data-testid="stHeader"] {{ visibility: hidden !important; }} .custom-sidebar {{ display: flex; flex-direction: column; height: 100vh; position: fixed; left: 0; top: 0; border-right: 1px solid rgba(59, 73, 75, 0.2); background-color: #0e0e0e; background-image: linear-gradient(to right, rgba(0, 240, 255, 0.02) 1px, transparent 1px), linear-gradient(to bottom, rgba(0, 240, 255, 0.02) 1px, transparent 1px); background-size: 32px 32px; width: 18rem; z-index: 999999; }} .sidebar-header {{ padding: 1.5rem; border-bottom: 1px solid rgba(59, 73, 75, 0.3); display: flex; align-items: center; gap: 1rem; overflow: hidden; }} .sidebar-logo {{ min-width: 2.5rem; height: 2.5rem; background-color: #2a2a2a; border: 1px solid rgba(59, 73, 75, 0.5); display: flex; align-items: center; justify-content: center; box-shadow: 0 0 4px rgba(0, 240, 255, 0.3), inset 0 0 4px rgba(0, 240, 255, 0.3); clip-path: polygon(0 0, calc(100% - 8px) 0, 100% 8px, 100% 100%, 0 100%); }} .sidebar-logo span {{ color: #dbfcff; }} .sidebar-title {{ font-family: 'Space Grotesk', sans-serif; font-size: 22px; font-weight: 900; letter-spacing: 0.1em; color: #dbfcff; margin: 0; line-height: 1; white-space: nowrap; }} .sidebar-subtitle {{ font-family: 'Space Mono', monospace; font-size: 10px; letter-spacing: 0.1em; font-weight: 700; color: #b9cacb; opacity: 0.7; margin: 4px 0 0 0; white-space: nowrap; }} .sidebar-links {{ flex: 1; overflow-y: auto; padding-top: 1.5rem; padding-bottom: 1.5rem; display: flex; flex-direction: column; gap: 0.5rem; padding-left: 1rem; padding-right: 1rem; }} .sidebar-link {{ display: flex; align-items: center; gap: 1rem; padding: 0.75rem 1rem; transition: all 0.3s ease-in-out; cursor: pointer; text-decoration: none; color: #b9cacb; opacity: 0.7; border-left: 4px solid transparent; }} .sidebar-link:hover {{ opacity: 1; background-color: rgba(219, 252, 255, 0.05); color: #dbfcff; box-shadow: 0 0 10px rgba(0,240,255,0.3); }} .sidebar-link.active {{ background-color: rgba(219, 252, 255, 0.1); color: #dbfcff; border-left-color: #dbfcff; box-shadow: inset 0 0 8px rgba(0,240,255,0.2); opacity: 1; }} .sidebar-link-text {{ font-family: 'Space Mono', monospace; font-size: 11px; letter-spacing: 0.2em; font-weight: 700; text-transform: uppercase; white-space: nowrap; }} .block-container {{ margin-left: 288px !important; max-width: calc(100% - 288px) !important; padding-top: 2rem !important; }} iframe[title="streamlit_components.v1.components.html"] {{ position: static !important; width: 100% !important; height: auto !important; border: none !important; }}</style><nav class="custom-sidebar"><div class="sidebar-header"><div class="sidebar-logo"><span class="material-symbols-outlined" style="font-variation-settings: 'FILL' 1;">terminal</span></div><div><h1 class="sidebar-title">STOCKIT</h1><p class="sidebar-subtitle">STRATEGY ENGINE</p></div></div><div class="sidebar-links">{links_html}</div></nav>"""
    return html
